import { isString } from 'lodash-es';
import { Children, type ReactNode } from 'react';

import { isComponent } from './is-component.js';
import { BubbleLayer } from '../components/BubbleLayer/BubbleLayer.js';
import { ChoroplethLayer } from '../components/ChoroplethLayer/ChoroplethLayer.js';
import { ConnectionLayer } from '../components/ConnectionLayer/ConnectionLayer.js';
import { DotLayer } from '../components/DotLayer/DotLayer.js';

const addCategory = (
  extendedDataPoint: Record<string, unknown>,
  valueAccessor?: string,
) => {
  if (valueAccessor && extendedDataPoint[valueAccessor]) {
    return extendedDataPoint[valueAccessor];
  }
};

const updateDomain = (
  domain: [number, number],
  value: number,
): [number, number] => {
  let [min, max] = domain;
  if (value < min) {
    min = value;
  }
  if (value > max) {
    max = value;
  }
  return [min, max];
};

/**
 * Extract layers data
 * @param children - MapView children
 * @param valueAccessors - MapView Layer valueAccessor
 * @returns flattened data array
 */
export const extractLayersData = (
  children: ReactNode,
  valueAccessors: Map<string, string>,
) => {
  let flattenData: Record<string, unknown>[] = [];
  const categoriesSet = new Set<string>();
  let legendDomain: [number, number] = [Infinity, -Infinity];

  Children.forEach(children, (child) => {
    if (isComponent(child, BubbleLayer) || isComponent(child, DotLayer)) {
      const { data } = child.props;

      data.forEach((dataPoint) => {
        const extendedDataPoint = {
          ...dataPoint,
          'layer-name': child.props.layerId,
        };

        const category = addCategory(
          extendedDataPoint,
          valueAccessors.get(child.props.layerId),
        );

        category && categoriesSet.add(category as string);

        if (typeof category === 'number') {
          legendDomain = updateDomain(legendDomain, category);
        }

        flattenData = flattenData.concat(extendedDataPoint);
      });
    } else if (isComponent(child, ConnectionLayer)) {
      const { data } = child.props;

      data.forEach((connection, connectionIndex) => {
        if (connection.path.length >= 2) {
          const category = addCategory(
            connection,
            valueAccessors.get(child.props.layerId),
          );

          category && categoriesSet.add(category as string);

          if (typeof category === 'number') {
            legendDomain = updateDomain(legendDomain, category);
          }

          connection.path.forEach((path, pathIndex) => {
            const parsedPath = {
              ...path,
              'connection-name': `connection-${connectionIndex + 1}`,
              'connection-item-index': pathIndex,
              'layer-name': child.props.layerId,
            };

            flattenData.push(parsedPath);
          });
        }
      });
    } else if (isComponent(child, ChoroplethLayer)) {
      const { data, regionAccessor } = child.props;

      data.forEach((dataEntry) => {
        const region = isString(regionAccessor)
          ? dataEntry[regionAccessor]
          : regionAccessor(dataEntry);

        const choroplethLayerData = {
          ...dataEntry,
          region,
          'layer-name': child.props.layerId,
        };

        const category = addCategory(
          choroplethLayerData,
          valueAccessors.get(child.props.layerId),
        );

        category && categoriesSet.add(category as string);

        if (typeof category === 'number') {
          legendDomain = updateDomain(legendDomain, category);
        }

        flattenData.push(choroplethLayerData);
      });
    }
  });

  return {
    flattenData,
    categories: [...categoriesSet],
    legendDomain,
  };
};
